import{_ as e,o as l,c as r,ak as o}from"./chunks/framework.BZTYhN8l.js";const h=JSON.parse('{"title":"Cloudflare 使用文档","description":"","frontmatter":{},"headers":[],"relativePath":"云服务/Cloudflare 文档.md","filePath":"云服务/Cloudflare 文档.md","lastUpdated":1775125132000}'),t={name:"云服务/Cloudflare 文档.md"};function d(i,a,n,s,c,p){return l(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="cloudflare-使用文档" tabindex="-1">Cloudflare 使用文档 <a class="header-anchor" href="#cloudflare-使用文档" aria-label="Permalink to “Cloudflare 使用文档”">​</a></h1><h2 id="一、概念" tabindex="-1">一、概念 <a class="header-anchor" href="#一、概念" aria-label="Permalink to “一、概念”">​</a></h2><p>Cloudflare 可以部署网站，有免费的CDN、证书、域名......，是一个免费的服务器</p><p>Cloudflare 官网地址</p><p><a href="https://dash.cloudflare.com/" target="_blank" rel="noreferrer">Cloudflare 官网</a></p><h2 id="二、项目部署" tabindex="-1">二、项目部署 <a class="header-anchor" href="#二、项目部署" aria-label="Permalink to “二、项目部署”">​</a></h2><h3 id="pages-部署应用-cloudflare-pages" tabindex="-1">Pages 部署应用 <a href="https://developers.cloudflare.com/pages/" target="_blank" rel="noreferrer">Cloudflare Pages</a> <a class="header-anchor" href="#pages-部署应用-cloudflare-pages" aria-label="Permalink to “Pages 部署应用 Cloudflare Pages”">​</a></h3><h4 id="本地文件上传-1000" tabindex="-1">本地文件上传 &lt; 1000 <a class="header-anchor" href="#本地文件上传-1000" aria-label="Permalink to “本地文件上传 &lt; 1000”">​</a></h4><p>步骤：Compute -&gt; Pages -&gt; 部署页面</p><ol><li>如果部署的文件数量小于 1000，可以直接创建应用名</li><li>直接拖动文件上传即可</li></ol><h4 id="wrangler-cli-加手脚推行-wrangler-cli-官方文档" tabindex="-1">wrangler cli 加手脚推行 <a href="https://developers.cloudflare.com/pages/get-started/direct-upload/#wrangler-cli" target="_blank" rel="noreferrer">Wrangler CLI 官方文档</a> <a class="header-anchor" href="#wrangler-cli-加手脚推行-wrangler-cli-官方文档" aria-label="Permalink to “wrangler cli 加手脚推行 Wrangler CLI 官方文档”">​</a></h4><ol><li>打包项目 <code>npm run build</code></li><li>临时安装使用 wrangler 并使用 <code>npx wrangler pages deploy dist</code></li><li>选择应用名进行推送</li></ol><blockquote><p>💡 tip：</p><p>本地推送文件至 Cloudflare 需要身份验证，windows 验证需要的 token 放在<br> C:\\Users\\UserName\\AppData\\Roaming\\xdg.config.wrangler\\config\\default.toml</p></blockquote>',13)])])}const g=e(t,[["render",d]]);export{h as __pageData,g as default};
